#include<bits/stdc++.h>
using namespace std;
int d[10001];

int find(int x) {
	if (d[x] == x) {
		return x;
	} else {
		return find(d[x]);
	}
}
void up(int x, int y) {
	int fx = find(x);
	int fy = find(y);
	d[fy] = fx;
}
int main() {
	int n, m, k;
	cin >> n >> m >> k;
	for (int i = 1; i <= n; i++) {
		d[i] = i;
	}
	for (int i = 1; i <= m; i++) {
		int x, y;
		cin >> x >> y;
		up(x, y);
	}
	for (int i = 1; i <= k; i++) {
		int x, y;
		cin>>x>>y;
		if(find(x)==find(y)){
			cout<<"Yes"<<"\n";
		}else{
			cout<<"No"<<"\n";
		}
	}
	return 0;
}
